from pathlib import Path
import pandas as pd
for p in Path('results').glob('*features*.csv'):
    try:
        df=pd.read_csv(p, nrows=1)
    except Exception as e:
        print(p, 'ERR', e); continue
    hits={pat:[c for c in df.columns if pat.lower() in c.lower()] for pat in ['FreeAcc','Roll','Pitch','Yaw','Euler','acc_e','free']}
    print('\n',p,'ncols',len(df.columns))
    for pat, cols in hits.items():
        if cols:
            print(' ',pat,len(cols),cols[:8])
